#include <iostream>
#include <string>
using namespace std;
string s,a;
int main(){
    while(cin>>a)s=s+a;
    int i=0,w=0,l=0;
    while(i<s.size() && s[i]!='E'){
        if(s[i]=='W')w++;
        else if(s[i]=='L')l++;
		if((w>=11 || l>=11) && (w-l>=2 || l-w>=2)){
			cout<<w<<':'<<l<<endl;
        	w=l=0;
        }
        i++;
    }
    cout<<w<<':'<<l<<endl<<endl;
    i=w=l=0;
    while(i<s.size() && s[i]!='E'){
		if(s[i]=='W')w++;
        else if(s[i]=='L')l++;
		if((w>=21 || l>=21) && (w-l>=2 || l-w>=2)){
			cout<<w<<':'<<l<<endl;
        	w=l=0;
        }
        i++;
    }
    cout<<w<<':'<<l;
    return 0;
}
